import { useQuery } from '@tanstack/react-query';
import { authService } from '@/api/auth/authService';
import type { PasswordPolicy } from '@/types/dto';
import { queryKeys } from '@/lib/queryKeys';

export function validatePassword(value: string, policy: PasswordPolicy): string | null {
  if (value.length < policy.minLength || value.length > policy.maxLength) {
    return policy.errorMessage;
  }
  return null;
}

export function usePasswordPolicy() {
  return useQuery({
    queryKey: queryKeys.passwordPolicy(),
    queryFn: () => authService.getPasswordPolicy(),
    staleTime: Infinity,
    gcTime: Infinity,
  });
}
